import * as cheerio from "cheerio";
import type { FeedConfig, FeedItem } from "../../types.js";

export async function fetchFeed(config: FeedConfig): Promise<FeedItem[]> {
  // 1. Fetch the listing page
  const resp = await fetch(config.url);
  const html = await resp.text();
  const $ = cheerio.load(html);

  // 2. Parse listing items from Webflow collection
  const cards = $("article.card_blog_list_wrap");
  const listingItems: Array<{
    title: string;
    url: string;
    publishedAt: string;
    id: string;
  }> = [];

  cards.each((_i, card) => {
    const $card = $(card);
    const title = $card.find(".card_blog_list_title").text().trim();
    const link = $card.find("a.clickable_link[href]").first();
    const href = link.attr("href") || "";
    const dateText = $card.find('[fs-list-field="date"]').text().trim();

    if (!title || !href) return;

    const fullUrl = href.startsWith("http")
      ? href
      : new URL(href, config.url).href;
    const publishedAt = dateText
      ? new Date(dateText).toISOString()
      : new Date().toISOString();
    const id = fullUrl;

    listingItems.push({ title, url: fullUrl, publishedAt, id });
  });

  // 3. Fetch each detail page in parallel for image + full content
  const items: FeedItem[] = await Promise.all(
    listingItems.map(async (item) => {
      try {
        const detailResp = await fetch(item.url);
        const detailHtml = await detailResp.text();
        const $detail = cheerio.load(detailHtml);

        // --- imageUrl: first <meta property="og:image"> ---
        const firstOgImage = $detail('meta[property="og:image"]')
          .first()
          .attr("content");
        const imageUrl = firstOgImage && !firstOgImage.includes("og_claude-generic")
          ? firstOgImage
          : undefined;

        // --- contentHtml: full inner HTML of .u-rich-text-blog ---
        const richText = $detail(".u-rich-text-blog")
          .filter((_i, el) => ($detail(el).text().trim().length > 50))
          .first();
        const contentHtml =
          richText.length > 0 ? richText.html() ?? undefined : undefined;

        return {
          source: config.slug,
          id: item.id,
          title: item.title,
          url: item.url,
          publishedAt: item.publishedAt,
          imageUrl,
          contentHtml,
        };
      } catch {
        // Degrade gracefully: return item without optional fields
        return {
          source: config.slug,
          id: item.id,
          title: item.title,
          url: item.url,
          publishedAt: item.publishedAt,
        };
      }
    }),
  );

  return items;
}
